                const v = edge.node;
                const weight = edge.weight;
                if (distEmpty[startNode][u] + weight < distEmpty[startNode][v]) {
                    distEmpty[startNode][v] = distEmpty[startNode][u] + weight;
                    pq.enqueue({ node: v, distance: distEmpty[startNode][v] });
                }
            }
        }
    }

    // Step 2: Calculate shortest path costs for returning with apples (Cost_return)
    // Cost_return[i][j] = minimum cost to travel from j back to i carrying apples.
    // The cost of an edge (u, v) with cost_i and tax_i when carrying apples is cost_i * tax_i.

    // Initialize adjacency list for return travel
    const adjReturn = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        const returnCost = cost * tax;
        // Roads are bidirectional, so the return cost applies both ways.
        adjReturn[u].push({ node: v, weight: returnCost });
        adjReturn[v].push({ node: u, weight: returnCost });
    }

    // APSP for return travel (N runs of Dijkstra's)
    const distReturn = Array(n).fill(0).map(() => Array(n).fill(INF));

    for (let startNode = 0; startNode < n; startNode++) {
        distReturn[startNode][startNode] = 0;
        const pq = new MinPriorityQueue({ priority: x => x.distance });
        pq.enqueue({ node: startNode, distance: 0 });

        while (!pq.isEmpty()) {
            const { node: u, distance: d } = pq.dequeue();

            if (d > distReturn[startNode][u]) continue;

            for (const edge of adjReturn[u]) {
                const v = edge.node;
                const weight = edge.weight;
                if (distReturn[startNode][u] + weight < distReturn[startNode][v]) {
                    distReturn[startNode][v] = distReturn[startNode][u] + weight;
                    pq.enqueue({ node: v, distance: distReturn[startNode][v] });
                }
            }
        }
    }

    // Step 3: Calculate the minimum total cost for each store i
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at store i
        let minCost = prices[i];

        // Option 2: Travel to store j, buy there, and return to i
        // Total Cost = Travel(i -> j, empty) + Price[j] + Travel(j -> i, with apples)
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Cost i -> j (empty)
            const costToJ = distEmpty[i][j];

            // Cost j -> i (with apples)
            const costBackToI = distReturn[j][i];

            if (costToJ !== INF && costBackToI !== INF) {
                // Total cost = Travel_empty(i->j) + Price[j] + Travel_return(j->i)
                const totalCost = costToJ + prices[j] + costBackToI;
                minCost = Math.min(minCost, totalCost);
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

// --- MinPriorityQueue Implementation for Dijkstra's Algorithm ---
// This implementation is necessary to make the solution self-contained and runnable.
class MinPriorityQueue {
    constructor({ priority }) {
        this._heap = [];
        this._priority = priority;
    }

    _getParentIndex(i) { return Math.floor((i - 1) / 2); }
    _getLeftChildIndex(i) { return 2 * i + 1; }
    _getRightChildIndex(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this._heap[i], this._heap[j]] = [this._heap[j], this._heap[i]];
    }

    isEmpty() {
        return this._heap.length === 0;
    }

    enqueue(element) {
        this._heap.push(element);
        this._bubbleUp(this._heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this._heap.length === 1) return this._heap.pop();

        const min = this._heap[0];
        this._heap[0] = this._heap.pop();
        this._bubbleDown(0);
        return min;
    }

    _bubbleUp(index) {
        let currentIndex = index;
        let parentIndex = this._getParentIndex(currentIndex);

        while (currentIndex > 0) {
            const currentPriority = this._priority(this._heap[currentIndex]);
            const parentPriority = this._priority(this._heap[parentIndex]);

            if (currentPriority < parentPriority) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
                parentIndex = this._getParentIndex(currentIndex);
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this._heap.length - 1;

        while (true) {
            let left = this._getLeftChildIndex(currentIndex);
            let right = this._getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (left <= lastIndex) {
                const currentPriority = this._priority(this._heap[smallest]);
                const leftPriority = this._priority(this._heap[left]);
                if (leftPriority < currentPriority) {
                    smallest = left;
                }
            }

            // Check right child
            if (right <= lastIndex) {
                const smallestPriority = this._priority(this._heap[smallest]);
                const rightPriority = this._priority(this._heap[right]);
                if (rightPriority < smallestPriority) {
                    smallest = right;
                }
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}
